// Empty by default. App boot will load saved entries from window.storage if present.
let SALES_DATA = [];
let INVENTORY_DATA = [];

// Persistence keys
const STORAGE_KEYS = {
  sales: 'shftx_sales_v1',
  inventory: 'shftx_inventory_v1',
  product_overrides: 'shftx_product_overrides_v1',  // user edits to PRODUCTS (img URL, prices, etc)
};

// Load saved data on boot
async function loadSavedData() {
  try {
    if (window.storage) {
      const sales = await window.storage.get(STORAGE_KEYS.sales).catch(() => null);
      if (sales && sales.value) SALES_DATA = JSON.parse(sales.value);
      const inv = await window.storage.get(STORAGE_KEYS.inventory).catch(() => null);
      if (inv && inv.value) INVENTORY_DATA = JSON.parse(inv.value);
      const overrides = await window.storage.get(STORAGE_KEYS.product_overrides).catch(() => null);
      if (overrides && overrides.value) {
        const map = JSON.parse(overrides.value);
        Object.entries(map).forEach(([id, fields]) => {
          const p = PRODUCTS.find(x => x.id === parseInt(id));
          if (p) Object.assign(p, fields);
        });
      }
    }
  } catch(e) { console.warn('Storage load failed', e); }
}

async function persistSales() {
  try { if (window.storage) await window.storage.set(STORAGE_KEYS.sales, JSON.stringify(SALES_DATA)); } catch(e){}
}
async function persistInventory() {
  try { if (window.storage) await window.storage.set(STORAGE_KEYS.inventory, JSON.stringify(INVENTORY_DATA)); } catch(e){}
}
async function persistProductOverrides() {
  try {
    if (!window.storage) return;
    const map = {};
    PRODUCTS.forEach(p => {
      const o = {};
      if (p.img) o.img = p.img;
      if (p._edited_cogs) o.cogs = p.cogs;
      if (p._edited_asp) o.asp = p.asp;
      if (p._edited_mrp) o.mrp = p.mrp;
      if (Object.keys(o).length) map[p.id] = o;
    });
    await window.storage.set(STORAGE_KEYS.product_overrides, JSON.stringify(map));
  } catch(e){}
}
